mapper.select:
SELECT ir.id, ir.inviter_user_id AS inviterUserId, inviter.username AS inviterUsername, ir.invitee_user_id AS inviteeUserId, invitee.username AS inviteeUsername, ir.invite_code AS inviteCode, ir.reward_status AS rewardStatus, ir.reward_granted_at AS rewardGrantedAt, ir.skip_reason AS skipReason, ir.trigger_biz_no AS triggerBizNo, ir.created_at AS createdAt FROM invite_relation ir LEFT JOIN blog_user inviter ON ir.inviter_user_id = inviter.id AND inviter.deleted_at IS NULL LEFT JOIN blog_user invitee ON ir.invitee_user_id = invitee.id AND invitee.deleted_at IS NULL WHERE ir.deleted_at IS NULL
AND ir.reward_status = #{rewardStatus}
AND ( inviter.username LIKE CONCAT('%', #{keyword}, '%') OR invitee.username LIKE CONCAT('%', #{keyword}, '%') OR ir.invite_code LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY ir.created_at DESC LIMIT #{limit} OFFSET #{offset}
